import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists(): return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing: existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]: existing[ch][v] = html

CHRIST = {
"19": {
"1": "<p>A direct type: The statute of the red heifer (<em>parah adumah</em>) is introduced as a <em>chukat hatorah</em> — a statute whose reason is not disclosed. Hebrews 9:13-14 reveals the logic: 'the ashes of a heifer sprinkle those who are ceremonially unclean so that they are outwardly clean — how much more will the blood of Christ, who through the eternal Spirit offered himself without blemish to God, purify our conscience.' The unexplained statute finds its explanation in Christ.</p>",
"2": "<p>A direct type: The red heifer must be without blemish (<em>temimah</em>) and must never have been yoked (<em>asher lo-ulah alehah ol</em>). Two requirements of perfection: moral purity and untouched freedom from servitude. Christ, 'a lamb without blemish' (1 Pet 1:19), had never been under sin's yoke — he was 'holy, innocent, unstained, separated from sinners' (Heb 7:26).</p>",
"3": "<p>A direct type: The heifer is slaughtered outside the camp (<em>el-mitzut lamachaneh</em>) and burned there. Hebrews 13:11-12 applies this directly: 'the bodies of those animals whose blood is brought into the holy places by the high priest as a sacrifice for sin are burned outside the camp. So Jesus also suffered outside the gate in order to sanctify the people through his own blood.' Golgotha was outside Jerusalem's walls.</p>",
"4": "<p>A direct type: Eleazar the priest sprinkles the blood seven times directly toward the tent of meeting. The seven-fold sprinkling toward the sanctuary is a priestly act of presenting the atoning blood before YHWH. Christ's blood was 'sprinkled to speak a better word than the blood of Abel' (Heb 12:24) — a blood that speaks peace, not vengeance.</p>",
"5": "<p>A direct type: The entire heifer is burned — hide, flesh, blood, and dung — outside the camp. The totality of the burning corresponds to Christ's total self-offering: body, blood, and the full weight of human sin (the dung representing the shameful elements). 'He himself bore our sins in his body' (1 Pet 2:24) — nothing was excluded from the bearing.</p>",
"6": "<p>A shadow: Cedar wood, hyssop, and scarlet thread are thrown into the burning — the same three elements used in the leper's cleansing (Lev 14:4) and the Passover (Exod 12:22). Together they form a cluster of cleansing imagery: cedar's elevation, hyssop's lowliness, scarlet's atoning color. Christ encompasses all: the exalted (cedar) who stooped (hyssop) and bled (scarlet).</p>",
"7": "<p>A theme: The priest who performs the red heifer ceremony becomes impure and must wash his clothes and bathe — made unclean by handling the purification offering. The paradox is theological: the agent of purification contracts impurity. Christ 'who knew no sin was made sin' (2 Cor 5:21) — the pure one became impure by contact with what he was purifying.</p>",
"8": "<p>A theme: The man who burns the heifer is also made unclean and must wash. The paradox extends: every participant in the purification ritual contracts defilement. Only the one who was already defiled becomes clean. This is the structure of the atonement: Christ takes our impurity upon himself; we receive his purity in exchange (2 Cor 5:21).</p>",
"9": "<p>A direct type: The ashes are gathered and kept for <em>mei niddah</em> — water of purification, water of cleansing. The ashes dissolved in water create the purification solution. Christ's accomplished sacrifice, applied by the Spirit (the living water), purifies the conscience: 'let us draw near with a true heart in full assurance of faith, with our hearts sprinkled clean from an evil conscience' (Heb 10:22).</p>",
"10": "<p>A shadow: The man who gathers the ashes also becomes unclean until evening. The contamination-transfer is complete throughout the ceremony: the officiants all bear impurity so the unclean may bear purity. This is the direction of Christ's entire ministry — he goes to where the unclean are (lepers, tax collectors, demoniacs) and the cleanness flows outward from him, not inward upon him.</p>",
"11": "<p>A theme: Touching a dead body makes one unclean for seven days. Death is the source of the deepest defilement in Israel's purity system. Christ entered into death itself — the deepest possible contact with impurity — and emerged from it having conquered it: 'Since therefore the children share in flesh and blood, he himself likewise partook of the same things, that through death he might destroy the one who has the power of death' (Heb 2:14).</p>",
"12": "<p>A theme: Purification from death-impurity must happen on the third day and the seventh day. The third-day pattern runs throughout the Old Testament (Hosea 6:2: 'after two days he will revive us; on the third day he will raise us up') and is fulfilled in Christ's resurrection 'on the third day' (1 Cor 15:4). The purification timeline points toward the resurrection timeline.</p>",
"13": "<p>A theme: Anyone who does not purify himself after contact with death 'defiles YHWH's tabernacle' — the impurity is not merely personal but corporate, threatening the dwelling place of God. Christ's atonement addresses this community dimension: his blood purifies not only individual consciences but 'the heavenly things themselves' (Heb 9:23).</p>",
"14": "<p>A theme: The law for the tent where someone dies: everyone in it is unclean for seven days. Death's contamination spreads through shared space. Adam's death spread to all who share human space: 'just as sin came into the world through one man, and death through sin, and so death spread to all men because all sinned' (Rom 5:12). The tent-death law is the liturgical form of original sin's logic.</p>",
"15": "<p>A theme: Every open vessel without a lid is unclean. The unsealed container is penetrated by death-impurity from the air. The metaphor of human vulnerability is striking: the open, unprotected vessel cannot remain clean in an environment of death. Only what is sealed is preserved. Christ seals his own with his Spirit (Eph 1:13-14; 2 Cor 1:22).</p>",
"16": "<p>A theme: Touching a bone, a grave, or a slain person in the open field contracts impurity. The open field — the uncontrolled terrain outside the camp — is where death and its defilements accumulate. Christ's ministry goes into the open field, the uncontrolled spaces: 'the Son of Man came to seek and save the lost' (Luke 19:10). He enters the field of defilement to bring purification.</p>",
"17": "<p>A direct type: Running water (<em>mayim chayim</em> — living water) is poured over the ashes in a vessel to make the purification water. <em>Mayim chayim</em> (living water) is the exact phrase Jesus uses to describe what he gives: 'whoever drinks the water I give him will never thirst again; the water I give him will become in him a spring of water welling up to eternal life' (John 4:14). The living water of the red heifer ceremony becomes the living water of the Spirit applied to the conscience.</p>",
"18": "<p>A shadow: A clean person takes hyssop, dips it in the water, and sprinkles it on the tent, vessels, and persons defiled. Hyssop — a small, low-growing plant — was the instrument for applying the blood at the Passover (Exod 12:22) and for David's prayer of cleansing (Ps 51:7: 'purge me with hyssop and I shall be clean'). At the cross, hyssop carries the sour wine to Jesus's lips (John 19:29). The plant of purification serves him who became the purification.</p>",
"19": "<p>A theme: The clean sprinkle the unclean; the sprinkler is then himself unclean until evening. The transmission of impurity runs in one direction: from death-contaminated to the clean agent. This reflects Christ's becoming sin — the clean one in contact with impurity absorbs it. But unlike the priest of the red heifer, Christ's impurity-absorption was permanent and substitutionary: he bore the uncleanness so the defiled could be permanently clean.</p>",
"20": "<p>A theme: The person who is unclean and does not purify himself — who despises the provision — is cut off from the assembly. The availability of purification makes its rejection culpable. The writer of Hebrews argues from greater to lesser: 'how much worse punishment do you think will be deserved by the one who has trampled underfoot the Son of God?' (Heb 10:29). The red heifer's provision foreshadows the greater provision whose rejection is correspondingly more serious.</p>",
"21": "<p>A theme: Handling the purification water makes one unclean until evening. The provision for cleansing is itself a source of impurity for the one who administers it — the paradox the entire chapter is built around. Paul knows this paradox as the apostle: 'we are the aroma of Christ... to one a fragrance from death to death, to the other a fragrance from life to life' (2 Cor 2:15-16). The same message that purifies the believing becomes the occasion of judgment for the unbelieving.</p>",
"22": "<p>A direct type: Whatever the unclean person touches becomes unclean; whoever touches it is unclean until evening. The chain of defilement stemming from death. Christ reversed the chain: when he touched the leper (Matt 8:3), the impurity did not flow from leper to Christ — healing flowed from Christ to leper. The chain of defilement became a chain of cleansing when the sinless one entered it.</p>"
},
"20": {
"1": "<p>A theme: The congregation arrives at Kadesh in the first month of the fortieth year — and Miriam dies there. The prophetic sister who watched over Moses in the basket (Exod 2:4) and led the women in song at the sea (Exod 15:20-21) ends her earthly journey at the wilderness threshold. The great three (Moses, Aaron, Miriam — Mic 6:4: 'I sent before you Moses, Aaron, and Miriam') are being called home before the crossing. The forerunners die outside the land; Christ enters it (the true land) and brings his people in.</p>",
"2": "<p>A theme: The assembly quarrels with Moses about water — the Meribah contention. The people's complaint 'would that we had died when our brothers died before YHWH' reveals their preference for dramatic martyrdom over ordinary suffering. The wilderness tests repeatedly expose the same idolatry of comfort. Christ in the wilderness 'was tempted in every way as we are, yet was without sin' (Heb 4:15) — he faced the same desert failures that Israel repeated throughout forty years.</p>",
"3": "<p>A theme: 'Why did you bring us up out of Egypt to bring us to this evil place?' The complaint against redemption itself — wishing to be back in bondage rather than forward through the wilderness. This is the spirit Paul warns against: 'I am afraid that as the serpent deceived Eve by his cunning, your thoughts will be led astray from a sincere and pure devotion to Christ' (2 Cor 11:3). The desire to return to Egypt is the desire to exchange the redeemer for the slave-master.</p>",
"4": "<p>A theme: The congregation's complaint about lack of water and grain and figs and pomegranates inverts the wilderness provision they have already received: manna, quail, water from rock (Exod 17). They are forgetting what was given in demanding what they lack. Christ addresses this directly: 'Do not be anxious about your life, what you will eat' (Matt 6:25). The kingdom does not run on Israel's accounting of its deficits.</p>",
"5": "<p>A theme: 'There is no water to drink.' The generation that received water from the rock at Horeb (Exod 17) is demanding water again. 1 Corinthians 10:4 identifies the rock at Horeb as Christ: 'they all drank from the spiritual rock that accompanied them, and that rock was Christ.' The same spiritual source that gave water the first time will give it the second time — but Moses's mishandling will cost him the land.</p>",
"6": "<p>A shadow: Moses and Aaron fall on their faces at the tent of meeting; the glory of YHWH appears. The crisis produces prayer and the presence of God, not immediately the provision. Christ in Gethsemane follows the same pattern: the extremity of need produces prostrate prayer, and the Father's presence sustains him through it (Luke 22:43-44). The falling-on-faces posture is the posture of the servant before the sovereign.</p>",
"7": "<p>A direct type: YHWH commands Moses: 'Take the staff and speak (<em>daber</em>) to the rock before their eyes, and it will give its water.' The staff and the spoken word: Moses is to speak, not strike. The second provision of water from the rock was to be accomplished by word, not force — pointing toward the Word who himself is the water. 'The words I have spoken to you are spirit and life' (John 6:63).</p>",
"8": "<p>A direct type: Moses is commanded to speak to the rock and it will yield water. The rock that was struck once at Horeb (Exod 17:6) was not to be struck again. Paul's typological insight in 1 Cor 10:4 suggests the reason: the rock = Christ, who was struck once ('once for all,' Heb 10:10). To strike the rock again is to act as if the first striking were insufficient — a denial of the once-for-all character of Christ's sacrifice.</p>",
"9": "<p>A shadow: Moses takes the staff as commanded. The rod of Moses's authority — used to part the sea, draw water, hold up against Amalek — here becomes the instrument of his downfall when wielded in anger rather than in obedience. Power and authority in YHWH's service require not just the right implement but the right spirit: 'Not by might, nor by power, but by my Spirit, says the Lord of hosts' (Zech 4:6).</p>",
"10": "<p>A shadow: Moses addresses the congregation: 'Hear now, you rebels — shall we bring water from this rock?' Two deviations from the command: he calls them rebels (usurping YHWH's role as judge) and says 'we' (attributing the miracle to himself and Aaron). Jesus addresses the disciples' analogous errors: 'apart from me you can do nothing' (John 15:5). The ministry belongs to the master; the servant's role is to serve, not to take possession.</p>",
"11": "<p>A theme: Moses strikes the rock twice with his staff and water comes out abundantly. The water still flows — YHWH's mercy is not withdrawn because of Moses's disobedience. The congregation drinks. The provision continues despite the servant's failure: 'If we are faithless, he remains faithful — for he cannot deny himself' (2 Tim 2:13). YHWH's faithfulness to the people does not depend on Moses's obedience.</p>",
"12": "<p>A direct type: YHWH says to Moses and Aaron: 'Because you did not believe in me (<em>lo-he'emantem bi</em>), to uphold my holiness (<em>lehaqdisheni</em>) before the eyes of Israel, therefore you shall not bring this assembly into the land.' The sin is failure to sanctify YHWH before the people — a failure of witness to his holiness. The high priest who failed to sanctify is replaced by one who perfectly sanctifies: Christ 'who sanctifies and those who are sanctified are all of one origin' (Heb 2:11).</p>",
"13": "<p>A direct type: These are the waters of Meribah (<em>merivah</em> = contention/strife), where Israel contended with YHWH, and through which YHWH showed himself holy. Christ at Calvary is the ultimate Meribah — the place of strife where God shows himself holy. The contention at the rock produces holy water; the contention at the cross produces holy blood: 'water and blood came out' (John 19:34).</p>",
"14": "<p>A theme: Moses sends messengers to Edom requesting passage through their territory, appealing to kinship ('your brother Israel'). Edom (Esau's descendants) and Israel (Jacob's descendants) are the divided brothers. The appeal to brotherhood across ancient division foreshadows the gospel's reconciliation: 'Christ Jesus... has made us both one and has broken down in his flesh the dividing wall of hostility' (Eph 2:13-14).</p>",
"15": "<p>A theme: 'You know all the trouble that has found us — our fathers went down to Egypt, we lived there a long time, and the Egyptians dealt harshly with us.' The appeal to shared history and memory. Christ appeals to a deeper shared history: 'before Abraham was, I am' (John 8:58). The story Moses rehearses to Edom is part of the larger story in which Christ is the main actor from before the foundation of the world.</p>",
"16": "<p>A theme: 'When we cried to YHWH, he heard our voice and sent an angel (<em>mal'akh</em>) and brought us out of Egypt.' The angel sent at the exodus (Exod 23:20-23 — 'my name is in him') is the pre-incarnate Christ whom Paul identifies as the rock that accompanied Israel (1 Cor 10:4). The wilderness guide who led Israel is the same one who now declares 'I am the way' (John 14:6).</p>",
"17": "<p>A shadow: Israel's request: 'Let us pass through your land. We will not pass through field or vineyard, or drink water from a well.' The careful, non-imposing request mirrors the gospel's non-coercive offer: 'Behold, I stand at the door and knock' (Rev 3:20). The kingdom does not seize passage by force; it requests it and accepts the answer. Edom will refuse; but not everyone does.</p>",
"18": "<p>A theme: Edom refuses: 'You shall not pass through.' The rejected passage request is the first of several rejections Israel faces at the land's border. Christ's own coming was similarly rejected: 'He came to his own, and his own people did not receive him' (John 1:11). The patterns of rejection that precede the conquest foreshadow the patterns that precede the kingdom.</p>",
"19": "<p>A shadow: Israel offers to pay for water if they drink it. The willingness to pay rather than take by right reflects the restraint of the redeemed: 'if anyone forces you to go one mile, go with him two miles' (Matt 5:41). The pilgrim posture of asking and offering is the posture of the kingdom in the world — not imposing its rights but seeking peaceful passage.</p>",
"20": "<p>A theme: Edom comes out against Israel with a large army. The armed refusal. Christ's coming produced armed hostility from those who felt threatened: Herod at the nativity (Matt 2:16), the Sanhedrin at the arrest, Pilate at the trial. The kingdom of peace enters a world that prefers controlled territory to offered salvation.</p>",
"21": "<p>A theme: Israel turns away from Edom. Not every obstacle is meant to be overcome by force. The wisdom to go around — to take the longer road — is the wisdom of the servant who knows when to press and when to give way. Christ's withdrawal to the wilderness and his strategic timing of the Passion reveal the same wisdom: 'His hour had not yet come' (John 7:30).</p>",
"22": "<p>A shadow: The congregation moves to Mount Hor, at the edge of Edom's land. Mount Hor is the site of the transition of the high priesthood from Aaron to Eleazar. The journey through the wilderness is punctuated by the deaths of leaders: Miriam at Kadesh (v1), Aaron at Hor (v23-29). The generation that came out of Egypt must pass away before the new generation inherits. Christ's death is the death that ends all priestly succession: 'he holds his priesthood permanently, because he continues forever' (Heb 7:24).</p>",
"23": "<p>A direct type: YHWH tells Moses at Mount Hor: 'Aaron shall be gathered to his people, for he shall not enter the land of Canaan, because you rebelled against my command at the waters of Meribah.' The announcement of Aaron's death is framed within the Meribah failure. The priesthood that depended on Aaron's mortal life was flawed from the beginning: 'if perfection had been attainable through the Levitical priesthood... what further need would there have been for another priest?' (Heb 7:11).</p>",
"24": "<p>A direct type: Aaron is 'gathered to his people' — the Hebrew idiom for death. Aaron the first high priest, whose ministry was inaugurated with great solemnity (Lev 8-9), dies at the wilderness edge. Every Aaronic high priest died (Heb 7:23: 'the former priests were many in number, because they were prevented by death from continuing in office'). Christ 'because he continues forever, holds his priesthood permanently' (Heb 7:24).</p>",
"25": "<p>A direct type: Moses takes Aaron and Eleazar up the mountain. The transfer ceremony: the dying priest, the new priest, and Moses as witness. The Levitical system requires this succession because death interrupts service. Christ's Melchizedekian priesthood (Ps 110:4; Heb 7) requires no succession: 'he always lives to make intercession' (Heb 7:25).</p>",
"26": "<p>A direct type: Moses strips Aaron's garments and puts them on Eleazar. The priestly garments — the ephod, the breastplate, the turban with its gold plate 'Holy to YHWH' — transfer from father to son. No such transfer occurs in Christ's high priesthood: he wears the permanent garments of divine sonship and sinless righteousness. The robe for which the soldiers cast lots (John 19:24) was his — and is now his in resurrection glory (Rev 1:13).</p>",
"27": "<p>A direct type: Aaron dies on the top of Mount Hor. The high priest dies on the mountain — outside the camp, above the people, in a high place. Christ dies on a hill outside Jerusalem. Both deaths are elevated, public, and transitional: Aaron's death transitions the priesthood to Eleazar; Christ's death transitions the entire priesthood to himself — and beyond.</p>",
"28": "<p>A shadow: Moses and Eleazar come down from the mountain. The mourning for Aaron is thirty days — the standard for a great leader (Moses will receive the same mourning, Deut 34:8). The death of the high priest releases the manslayer from the city of refuge (Num 35:25). Christ's death releases every sinner from the greater confinement: 'it is for freedom that Christ has set us free' (Gal 5:1).</p>",
"29": "<p>A direct type: The whole congregation weeps for Aaron thirty days. The mourning of the whole assembly for the high priest. Zechariah 12:10-11 prophesies a greater mourning for a greater death: 'they will look on me, the one they have pierced, and they will mourn for him as one mourns for an only child.' The mourning for Aaron is a forerunner of the mourning that greets the recognition of the crucified Christ.</p>"
},
"21": {
"1": "<p>A shadow: The Canaanite king of Arad hears Israel is coming and attacks — capturing some of them. The first military engagement at the land's border goes to the enemy. Israel vows a <em>cherem</em> (complete destruction) if YHWH gives Arad over. The cherem vow — total dedication of the enemy to YHWH's destruction — mirrors the complete victory Christ wins: 'he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him' (Col 2:15). The cherem offers nothing for self; all goes to YHWH.</p>",
"2": "<p>A shadow: Israel vows: 'If you will indeed give this people into my hand, I will devote their cities to destruction.' The conditional vow — everything for YHWH, nothing for us. This is the prayer of total surrender that Christ embodies: 'Not my will, but yours' (Luke 22:42). The <em>cherem</em> victory is the victory of those who hold nothing back.</p>",
"3": "<p>A shadow: YHWH hears Israel's voice and gives the Canaanites over. The vow is fulfilled: the cities are utterly destroyed. The immediate answer to the conditional prayer of total dedication mirrors the pattern of Christ's prayer: 'Father, glorify your name. Then a voice came from heaven: I have glorified it, and I will glorify it again' (John 12:28). The surrendered prayer is always heard.</p>",
"4": "<p>A theme: They set out from Mount Hor by the way to the Red Sea to go around Edom, and the people became impatient (<em>vatiketzer nefesh</em> — the soul became short). The soul's shortness — the inability to bear the long way — is the wilderness test that fells generation after generation. Paul's appeal: 'let us not grow weary of doing good, for in due season we will reap, if we do not give up' (Gal 6:9). Christ 'endured the cross, despising the shame' (Heb 12:2) — the soul that does not become short.</p>",
"5": "<p>A theme: The people speak against God and Moses: 'Why have you brought us up out of Egypt to die in the wilderness? For there is no food and no water, and we loathe this worthless food.' They loathe the manna — the supernatural provision that sustained them for forty years. 1 Corinthians 10:10 cites this as a warning: 'do not grumble, as some of them did and were destroyed.' The rejection of the bread from heaven foreshadows the rejection of the Bread of Life (John 6:66: 'after this many of his disciples turned back').</p>",
"6": "<p>A direct type: YHWH sends fiery serpents (<em>hanechashim hasrafim</em>) — their bite brings death. The serpent — the instrument of the fall (Gen 3:1-5) — is now YHWH's instrument of judgment. 'The wages of sin is death' (Rom 6:23). The serpents bring into the visible world what the people's sin already deserved: the lethal consequence of rejecting the provision of God.</p>",
"7": "<p>A direct type: The people confess: 'We have sinned, for we spoke against YHWH and against you. Pray to YHWH that he take away the serpents.' The threefold movement of repentance: confession of sin, acknowledgment of those sinned against, petition for removal of judgment. Christ's response to repentance is identical across Testaments: 'your sins are forgiven' (Mark 2:5). The prayer of the bitten — 'take away the serpents' — is the prayer Christ answers in a way surpassing their imagination.</p>",
"8": "<p>A direct type: YHWH commands Moses to make a bronze serpent (<em>nachash nechoshet</em>) and set it on a pole (<em>nes</em>). Jesus explicitly interprets this verse: 'Just as Moses lifted up the serpent in the wilderness, so must the Son of Man be lifted up, that whoever believes in him may have eternal life' (John 3:14-15). The bronze serpent on the pole is the most explicit type of the cross in the entire Torah. The serpent — the symbol of sin, the instrument of death — is lifted up and becomes the means of life.</p>",
"9": "<p>A direct type: Everyone bitten who looks at the bronze serpent lives. The mechanism is faith-action: look and live. No merit, no performance, no payment — only the act of looking toward what was lifted up. John 3:15-16 preserves the exact parallel: 'whoever believes in him may have eternal life.' The bite is the wound that cannot be self-healed; the look is the faith that cannot self-generate its object — Christ must be lifted up before there is anything to look to.</p>",
"10": "<p>A shadow: Israel sets out and camps at Oboth, then Iye-abarim. The itinerary resumes after the serpent episode — the journey continues, the camp moves, the people travel. Life after the look at the bronze serpent is not static: the one who has been healed gets up and moves toward the promised land. Salvation does not end the journey; it enables it.</p>",
"11": "<p>A shadow: Oboth to Iye-abarim in the wilderness on the east side of Moab, toward the sunrise. The directional orientation — toward the sunrise, <em>mizrach</em> — carries a note of hope throughout the wilderness itinerary. Isaiah 9:2 and Luke 1:78 use the sunrise as a metaphor for the Messiah: 'the sunrise shall visit us from on high, to give light to those who sit in darkness.'</p>",
"12": "<p>A shadow: From there they set out and camped in the Valley of Zered. The Zered Wadi was the boundary between Moab and Edom, marking a significant geographic transition in the approach to Canaan. The wilderness journey has stages of progress, each marked by YHWH's leading. As Israel's journey is stagelike, so the redemptive journey of each believer: 'from one degree of glory to another' (2 Cor 3:18).</p>",
"13": "<p>A shadow: They set out from there and camped on the other side of the Arnon — the border of Moab between Moab and the Amorites. The Arnon becomes the line that separates the settled Transjordanian territory from the open wilderness. Each border crossed in the wilderness narrative is a step closer to the inheritance: a geography of progressive approach. The kingdom also comes by stages: 'already and not yet.'</p>",
"14": "<p>A shadow: The itinerary quotes the Book of the Wars of YHWH — an ancient source no longer extant. The battles are YHWH's wars, not merely Israel's military campaigns. Christ's battles are the same: 'the Lord will fight for you' (Exod 14:14). The reference to an older source reminds that the redemption story was already being told before Numbers; it will be told after Revelation.</p>",
"15": "<p>A shadow: The geographic markers from the Book of the Wars: Waheb and the wadis that slope to Ar. The careful topography testifies that the wilderness journey was real and documentable — not myth but history. The incarnation is equally historical: 'we have heard, we have seen with our eyes, we have looked upon and touched with our hands' (1 John 1:1). The salvation of YHWH happens in real geography.</p>",
"16": "<p>A direct type: From there they came to Beer (<em>be'er</em> — well). YHWH says: 'Gather the people together, so that I may give them water.' The gift of water from the well foreshadows John 4 (Jacob's well) and John 7:37-38: 'let anyone who is thirsty come to me and drink. Whoever believes in me, as the Scripture has said, out of his heart will flow rivers of living water.' YHWH's provision of wells across the wilderness is the material form of the spiritual provision Christ embodies.</p>",
"17": "<p>A direct type: Israel sings the well song: 'Spring up, O well! — sing to it! — the well that the princes dug, that the nobles of the people delved, with the scepter and with their staffs.' The song over the well given by YHWH through human labor. 1 Corinthians 10:4 identifies this provision: 'the spiritual rock that accompanied them... was Christ.' The well song is a song to Christ, though Israel did not yet know his name.</p>",
"18": "<p>A shadow: Mattanah, Nahaliel, Bamoth — stages along the route from Beer. The names themselves carry meaning: <em>mattanah</em> (gift), <em>nahaliel</em> (river of God), <em>bamoth</em> (heights). The stages of the journey trace a path of gift, then river, then heights — a pattern that mirrors the spiritual journey: gift of grace, the river of the Spirit, the heights of the kingdom.</p>",
"19": "<p>A shadow: Bamoth to the valley in the field of Moab, at the top of Pisgah overlooking the desert. Pisgah is where Moses will see the promised land before his death (Deut 34:1). The same heights that will show Moses what he cannot enter are stages in the journey leading there. The view from Pisgah — the vision of the inheritance without the entry — is the type of the prophets who saw from afar what they did not receive (Heb 11:13).</p>",
"20": "<p>A theme: Israel encamped at the top of Pisgah overlooking the desert. The wilderness seen from the heights: the terrain they have crossed, still visible behind them. Paul's backward glance at what was lost: 'forgetting what lies behind and straining forward to what lies ahead, I press on toward the goal' (Phil 3:13-14). The view from Pisgah is both backward (wilderness) and forward (Canaan).</p>",
"21": "<p>A shadow: Israel sends messengers to Sihon king of the Amorites: 'Let me pass through your land. We will not turn aside into field or vineyard... until we have passed through your territory.' The same diplomatic request sent to Edom (ch20:17) is repeated. The refusal to impose while passing through — the posture of the kingdom in a hostile world: 'be wise as serpents and innocent as doves' (Matt 10:16).</p>",
"22": "<p>A shadow: Israel will travel only on the king's highway — the main road, public and documented. The commitment to transparent travel, accountable and open. Christ's ministry was similarly public: 'I have spoken openly to the world; I have always taught in synagogues and in the temple... I have said nothing in secret' (John 18:20).</p>",
"23": "<p>A shadow: Sihon refuses passage and attacks Israel with all his army at Jahaz. Unlike Edom, Sihon acts aggressively — he does not merely refuse but initiates warfare. The transition from refusal to attack is the escalation of resistance to the kingdom's advance. Every generation experiences those who do not merely decline the gospel but actively oppose it.</p>",
"24": "<p>A shadow: Israel strikes Sihon with the edge of the sword and takes possession of his land from the Arnon to the Jabbok. The victory is total and swift after Sihon's aggression. Christ's victory over the powers is similarly decisive and total: 'he disarmed the rulers and authorities and put them to open shame, triumphing over them in him' (Col 2:15).</p>",
"25": "<p>A shadow: Israel settles in Heshbon and all Sihon's towns. The occupation of what was won — the taking up of residence in the victory. The settled occupation of Sihon's land foreshadows the eternal rest: 'there remains a Sabbath rest for the people of God' (Heb 4:9). The conquest rest is the type of the eschatological rest.</p>",
"26": "<p>A theme: Heshbon was Sihon's city, who defeated the former king of Moab. The geography of victory builds on prior victories. Each defeat of a prior king makes way for the next. The redemptive narrative accumulates victories: each type and shadow of Christ's work adds to the full picture. Nothing is isolated; each event is a layer in a building argument about YHWH's faithfulness.</p>",
"27": "<p>A shadow: A taunt song about Heshbon — 'come to Heshbon, let it be built.' Ancient victory songs over defeated enemies. The song of Moses at the sea (Exod 15), the song of Deborah (Judg 5), the Psalms of ascent — Israel sings its way through history. Revelation continues this: the song of Moses and the song of the Lamb (Rev 15:3) will be the final victory song.</p>",
"28": "<p>A shadow: 'For fire came out from Heshbon, flame from the city of Sihon. It consumed Ar of Moab, the lords of the heights of the Arnon.' The fire of judgment spreading from the conquered city to the surrounding nations. The imagery anticipates the eschatological fire of YHWH's judgment: 'our God is a consuming fire' (Heb 12:29).</p>",
"29": "<p>A shadow: 'Woe to you, O Moab!' — the taunt song against the nation that worships Chemosh. The lament over Moab's idol-worship is the lament over all idolatry: the substitution of a dead god for the living one. Christ's lament over Jerusalem (Luke 19:41-44) echoes the prophetic lament here: the city that rejects YHWH's ways will be given over to destruction.</p>",
"30": "<p>A shadow: Heshbon is overthrown to Dibon, the women of Moab wailing. The devastation is total; the mourning is real. The conquest narratives of Numbers 21 are not triumphalist pageantry but the serious displacement that results when idolatrous kingdoms resist YHWH's purposes. Christ's warnings about Jerusalem (Matt 24) have the same tone: not joy at destruction but necessity when resistance is total.</p>",
"31": "<p>A shadow: Israel settled in the land of the Amorites. The settlement is a foretaste of the final settlement — the rest after the wilderness, the dwelling in the promised land. Every time Israel establishes a camp or a settlement, it is a temporary version of the permanent rest Christ secures: 'I go to prepare a place for you' (John 14:2).</p>",
"32": "<p>A shadow: Moses sent men to spy out Jazer; they captured its towns and dispossessed the Amorites. The systematic extension of the victory — town by town, each captured and possessed. The kingdom spreads the same way: 'the kingdom of heaven is like leaven that a woman took and hid in three measures of flour, till it was all leavened' (Matt 13:33). Incremental, comprehensive, unstoppable.</p>",
"33": "<p>A shadow: They turned and went up the road to Bashan; Og king of Bashan came out against them. Og of Bashan — the last of the Rephaim (Deut 3:11), a giant whose iron bed was nine cubits long — represents the most fearsome final enemy before the Jordan. Paul's language for the powers that oppose the gospel invokes similar categories: 'the rulers, the authorities, the cosmic powers over this present darkness' (Eph 6:12).</p>",
"34": "<p>A direct type: YHWH says to Moses: 'Do not fear him, for I have given him into your hand, and all his people, and his land.' The divine assurance before the battle: 'I have given him' — YHWH's announcement of victory precedes the engagement. This is the grammar of the resurrection: 'If God is for us, who can be against us?' (Rom 8:31). The battle is fought in the knowledge of the already-given outcome.</p>",
"35": "<p>A shadow: They struck him and his sons and all his people until not one was left, and they possessed his land. The total victory over Og — the final Rephaim, the last remnant of the ancient giants. The comprehensive defeat of the strongest enemy signals that no obstacle remains to the crossing. Christ's resurrection is the comprehensive defeat of the last enemy: 'the last enemy to be destroyed is death' (1 Cor 15:26). After the final enemy falls, the inheritance opens.</p>"
}
}

comm = load_comm('mkt-christ', 'numbers')
